import React from "react";

const TestimonialCard = ({ testimonial }) => {
  const { name, rating, text, img } = testimonial;

  return (
    <div style={{ flex: 1, border: "1px solid #ccc", borderRadius: "1rem", padding: "1rem", textAlign: "center" }}>
      <img
        src={img}
        alt={`Foto de ${name}`}
        style={{ width: "120px", height: "120px", borderRadius: "50%", marginBottom: "1rem", objectFit: "cover" }}
      />
      <div style={{ color: "#F2B33D", marginBottom: "0.5rem" }}>
        {"★".repeat(rating) + "☆".repeat(5 - rating)} {/* Simple star rating */}
      </div>
      <p style={{ fontSize: "0.9rem", lineHeight: "1.4" }}>"{text}"</p>
      <b style={{ display: "block", marginTop: "1rem" }}>{name}</b>
    </div>
  );
};

export default TestimonialCard;
